content.content:
1:/**
2: * The Spider — rig execution engine apparatus.
3: *
4: * The Spider drives writ-to-completion by managing rigs: ordered pipelines
5: * of engine instances. Each crawl() call performs one unit of work:
6: *
7: *   collect > checkBlocked > run > spawn   (priority order)
8: *
9: * collect      — check running engines for terminal session results
10: * checkBlocked — poll registered block type checkers; unblock engines when cleared
11: * run          — execute the next pending engine (clockwork inline, quick → launch)
12: * spawn        — create a new rig for a ready writ with no existing rig
13: *
14: * CDC on the rigs book (Phase 1 cascade) transitions the associated writ
15: * when a rig reaches a terminal state (completed or failed).
16: * The blocked status does NOT trigger the CDC handler.
17: *
18: * See: docs/architecture/apparatus/spider.md
19: */
21:import type { Plugin, StartupContext, LoadedPlugin, LoadedKit, LoadedApparatus } from '@shardworks/nexus-core';
22:import { guild, generateId, isLoadedKit, isLoadedApparatus } from '@shardworks/nexus-core';
23:import type { StacksApi, Book, ReadOnlyBook, WhereClause } from '@shardworks/stacks-apparatus';
24:import type { ClerkApi, WritDoc } from '@shardworks/clerk-apparatus';
25:import type { FabricatorApi } from '@shardworks/fabricator-apparatus';
26:import type { SessionDoc } from '@shardworks/animator-apparatus';
28:import type {
29:  RigDoc,
30:  RigFilters,
31:  EngineInstance,
32:  SpiderApi,
33:  CrawlResult,
34:  SpiderConfig,
35:  BlockRecord,
36:  BlockType,
37:  BlockTypeInfo,
38:  CheckResult,
39:  RigTemplate,
40:  RigTemplateInfo,
41:} from './types.ts';
43:import {
44:  draftEngine,
45:  implementEngine,
46:  reviewEngine,
47:  reviseEngine,
48:  sealEngine,
49:} from './engines/index.ts';
51:import {
52:  writStatusBlockType,
53:  scheduledTimeBlockType,
54:  bookUpdatedBlockType,
55:  patronInputBlockType,
56:} from './block-types/index.ts';
58:import {
59:  crawlOneTool,
60:  crawlContinualTool,
61:  rigShowTool,
62:  rigListTool,
63:  rigForWritTool,
64:  rigResumeTool,
65:  inputRequestListTool,
66:  inputRequestShowTool,
67:  inputRequestAnswerTool,
68:  inputRequestCompleteTool,
69:  inputRequestRejectTool,
70:  inputRequestExportTool,
71:  inputRequestImportTool,
72:  engineDesignsTool,
73:  blockTypesTool,
74:} from './tools/index.ts';
76:import { spiderRoutes } from './oculus-routes.ts';
78:// ── Kit contribution interface ─────────────────────────────────────────
80:/** Kit contribution interface for the Spider's rig template system. */
81:export interface SpiderKit {
82:  /** Named rig templates. Keys are unqualified; registered as pluginId.key. */
83:  rigTemplates?: Record<string, RigTemplate>;
84:  /** Writ type → rig template name mappings. Keys are unqualified writ type names. */
85:  rigTemplateMappings?: Record<string, string>;
86:}
88:// ── Helpers ────────────────────────────────────────────────────────────
90:/**
91: * Check whether a value is JSON-serializable.
92: * Non-serializable yields cause engine failure — the Stacks cannot store them.
93: */
94:function isJsonSerializable(value: unknown): boolean {
95:  try {
96:    JSON.stringify(value);
97:    return true;
98:  } catch {
99:    return false;
100:  }
101:}
103:/**
104: * Build the upstream yields map for a rig: all completed engine yields
105: * keyed by engine id. Passed as context.upstream to the engine's run().
106: */
107:function buildUpstreamMap(rig: RigDoc): Record<string, unknown> {
108:  const upstream: Record<string, unknown> = {};
109:  for (const engine of rig.engines) {
110:    if (engine.status === 'completed' && engine.yields !== undefined) {
111:      upstream[engine.id] = engine.yields;
112:    }
113:  }
114:  return upstream;
115:}
117:/**
118: * Find the first pending engine whose entire upstream is completed.
119: * Returns null if no runnable engine exists.
120: */
121:function findRunnableEngine(rig: RigDoc): EngineInstance | null {
122:  for (const engine of rig.engines) {
123:    if (engine.status !== 'pending') continue;
124:    const allUpstreamDone = engine.upstream.every((upstreamId) => {
125:      const dep = rig.engines.find((e) => e.id === upstreamId);
126:      return dep?.status === 'completed';
127:    });
128:    if (allUpstreamDone) return engine;
129:  }
130:  return null;
131:}
133:/**
134: * Determine whether a rig should enter the blocked state.
135: *
136: * A rig is blocked when:
137: * - No engine is currently running
138: * - No engine is runnable (pending with all upstream completed)
139: * - At least one engine is blocked
140: */
141:function isRigBlocked(engines: EngineInstance[]): boolean {
142:  const hasRunning = engines.some((e) => e.status === 'running');
143:  if (hasRunning) return false;
144:  const hasBlocked = engines.some((e) => e.status === 'blocked');
145:  if (!hasBlocked) return false;
