103:/**
104: * Build the upstream yields map for a rig: all completed engine yields
105: * keyed by engine id. Passed as context.upstream to the engine's run().
106: */
107:function buildUpstreamMap(rig: RigDoc): Record<string, unknown> {
108:  const upstream: Record<string, unknown> = {};
109:  for (const engine of rig.engines) {
110:    if (engine.status === 'completed' && engine.yields !== undefined) {
111:      upstream[engine.id] = engine.yields;
112:    }
113:  }
114:  return upstream;
115:}
117:/**
118: * Find the first pending engine whose entire upstream is completed.
119: * Returns null if no runnable engine exists.
120: */
121:function findRunnableEngine(rig: RigDoc): EngineInstance | null {
122:  for (const engine of rig.engines) {
123:    if (engine.status !== 'pending') continue;
124:    const allUpstreamDone = engine.upstream.every((upstreamId) => {
125:      const dep = rig.engines.find((e) => e.id === upstreamId);
126:      return dep?.status === 'completed';
127:    });
128:    if (allUpstreamDone) return engine;
129:  }
130:  return null;
131:}
