1385:        // CDC — Phase 1 cascade on rigs book.
1386:        // When a rig reaches a terminal state, transition the associated writ.
1387:        // The 'blocked' status intentionally falls through — no CDC action.
1388:        stacks.watch<RigDoc>(
1389:          'spider',
1390:          'rigs',
1391:          async (event) => {
1392:            if (event.type !== 'update') return;
