1397:            // Only act when status changes to a terminal state
1398:            if (rig.status === prev.status) return;
1400:            if (rig.status === 'completed') {
1401:              let resolutionYields: unknown;
1403:              // 1. Try the declared resolution engine
1404:              if (rig.resolutionEngineId) {
1405:                const declared = rig.engines.find((e) => e.id === rig.resolutionEngineId);
1406:                if (declared?.yields !== undefined) {
1407:                  resolutionYields = declared.yields;
1408:                }
1409:              }
1411:              // 2. Fall back to seal engine (backwards compat for pre-existing rigs)
1412:              if (resolutionYields === undefined) {
1413:                const seal = rig.engines.find((e) => e.id === 'seal');
1414:                if (seal?.yields !== undefined) {
1415:                  resolutionYields = seal.yields;
1416:                }
1417:              }
1419:              // 3. Fall back to last completed engine in array order
1420:              if (resolutionYields === undefined) {
1421:                const lastCompleted = [...rig.engines]
1422:                  .reverse()
1423:                  .find((e) => e.status === 'completed' && e.yields !== undefined);
1424:                if (lastCompleted) {
1425:                  resolutionYields = lastCompleted.yields;
1426:                }
1427:              }
1429:              const resolution = resolutionYields !== undefined
1430:                ? JSON.stringify(resolutionYields)
1431:                : 'Rig completed';
